#include<cstdio>
#include<vector>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res; 
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=5005;std::vector<int> G[N<<1],in,ou;
int dfn[N<<1],low[N<<1],scc[N<<1],stk[N<<1],top,tot,cdt,ans=1,n;bool iss[N<<1],q[N][N];int a[N];
inline void tarjan(const int &u)
{
	iss[stk[++top]=u]=true;dfn[u]=low[u]=++cdt;
	for(int v:G[u])if(!dfn[v]){tarjan(v);low[u]=min(low[u],low[v]);} else if(iss[v])low[u]=min(low[u],low[v]);
	if(low[u]==dfn[u]){++tot;int v;do iss[v=stk[top--]]=false,scc[v]=tot;while(v!=u);}
}
int main()
{
	if((n=read())==2)return puts("2"),0;
	rep(1,n,u)
	{
		int k=read();while(k--)q[u][read()]=true;
		rep(1,n,v)if(u!=v)q[u][v]?G[u+n].push_back(v):G[u].push_back(v+n);
	}
	rep(1,n<<1,i)if(!dfn[i])tarjan(i);
	rep(1,n,i)if(scc[i]==scc[i+n])return puts("0"),0;
	rep(1,n,i)(scc[i]<scc[i+n]?in:ou).push_back(i);
	for(int u:in){int cnt=0;for(int v:ou)if(q[u][v]){if(cnt==1){a[u]=-1;break;}++cnt;a[u]=v;}}
	for(int u:ou){int cnt=0;for(int v:in)if(!q[u][v]){if(cnt==1){a[u]=-1;break;}++cnt;a[u]=v;}}
	if(in.size()!=1)for(int u:in)ans+=(!a[u]);if(ou.size()!=1)for(int u:ou)ans+=!(a[u]);
	for(int u:in)for(int v:ou)ans+=((a[u]==v||!a[u])&&(a[v]==u||!a[v]));
	printf("%d\n",ans);return 0;
}
